sqlMap.insert:
INSERT INTO tbl_attitude ( ATTITUDE_ID, COMPANY_ID, TENANT_ID, WRITER_ID, DEPT_ID, START_DATE, END_DATE, REGION, MOBILE, BIZSUB, CONTENT, IP, DATE_TYPE, TYPE_ID, MODAPPL
,WORK_STATUS
) VALUES ( SEQ_TBL_ATTITUDE.nextval, #companyId#, #tenantId#, #writerId#, #deptId#, TO_DATE(#startDate#, 'YYYY-MM-DD HH24:MI:SS') - #offsetMin# / (24 * 60), CASE WHEN #endDate# = '' THEN null ELSE TO_DATE(#endDate#, 'YYYY-MM-DD HH24:MI:SS') - #offsetMin# / (24 * 60) END, NVL(#region#, ''), NVL(#mobile#, ''), NVL(#bizSub#, ''), NVL(#content#, ''), NVL(#ipAddress#, ''), #dateType#, #typeId#, #modappl#
,#workStatus#
)
SELECT SEQ_TBL_ATTITUDE.currval FROM dual

sqlMap.select:
SELECT * FROM ( SELECT T1.*, ROWNUM AS RN FROM ( SELECT a.attitude_id as ATTITUDE_ID, TO_CHAR(a.change_date + #offset# / (24 * 60), 'YYYY-MM-DD HH24:MI:SS') as CHANGE_DATE, CASE #lang# WHEN '2' THEN a.appr_user_name2 ELSE a.appr_user_name END AS APPR_USER_NAME, TO_CHAR(a.origin_date + #offset# / (24 * 60), 'YYYY-MM-DD HH24:MI:SS') as START_DATE, a.appr_status as APPR_STATUS, CASE #lang# WHEN '2' THEN a.writer_name2 ELSE a.writer_name END AS WRITER_NAME, CASE #lang# WHEN '2' THEN a.writer_dept_name2 ELSE a.writer_dept_name END AS WRITER_DEPT_NAME, a.appl_cnt AS APPL_CNT, a.writer_id as WRITER_ID, TO_CHAR(a.appl_date + #offset# / (24 * 60), 'YYYY-MM-DD HH24:MI:SS') as APPL_DATE FROM tbl_attitude_modappl a inner join tbl_attitude b on a.ATTITUDE_ID = b.ATTITUDE_ID and a.COMPANY_ID = b.COMPANY_ID and a.TENANT_ID = b.TENANT_ID where a.COMPANY_ID = #companyId# and a.TENANT_ID = #tenantId# and a.writer_id NOT IN (SELECT cn FROM TBL_USERMASTER_RETIRE WHERE TENANT_ID = #tenantId#)
) T1 )
WHERE RN <= #endRow# AND RN >= #startRow#

SELECT * FROM ( SELECT T1.*, ROWNUM AS RN FROM ( SELECT a.attitude_id as ATTITUDE_ID, to_char(b.end_date + #offset# / (24 * 60), 'YYYY-MM-DD HH24:MI:SS') AS CHANGE_DATE, CASE #lang# WHEN '2' THEN a.APPR_USER_NAME2 ELSE a.APPR_USER_NAME END AS APPR_USER_NAME, to_char(b.start_date + #offset# / (24 * 60), 'YYYY-MM-DD HH24:MI:SS') AS START_DATE, a.appr_status as APPR_STATUS, c.type_id AS TYPE_ID, CASE #lang# WHEN '2' THEN c.type_name2 ELSE c.type_name END AS TYPE_NAME, CASE #lang# WHEN '2' THEN a.WRITER_NAME2 ELSE a.WRITER_NAME END AS WRITER_NAME, CASE #lang# WHEN '2' THEN a.WRITER_DEPT_NAME2 ELSE a.WRITER_DEPT_NAME END AS WRITER_DEPT_NAME, a.appl_cnt AS APPL_CNT, a.writer_id as WRITER_ID, to_char(A.appl_date + #offset# / (24 * 60), 'YYYY-MM-DD HH24:MI:SS') AS APPL_DATE FROM TBL_ATTITUDE_ANNUAL_CANAPPL a inner join TBL_ATTITUDE b on a.ATTITUDE_ID = b.ATTITUDE_ID inner join TBL_ATTITUDE_TYPE c on b.TYPE_ID = c.TYPE_ID and a.COMPANY_ID = c.COMPANY_ID and a.TENANT_ID = c.TENANT_ID where a.COMPANY_ID = #companyId# and a.TENANT_ID = #tenantId# and a.writer_id NOT IN (SELECT cn FROM TBL_USERMASTER_RETIRE WHERE TENANT_ID = #tenantId#)
) T1 )
WHERE RN <= #endRow# AND RN >= #startRow#
